import React, { useState, useEffect } from 'react';
import { createRoot } from 'react-dom/client';

const AI = 'http://localhost:8000';

function Badge({variant,children}:any) { const c:any={success:'#dcfce7,#16a34a',warning:'#fef3c7,#d97706',error:'#fee2e2,#dc2626',info:'#dbeafe,#2563eb',neutral:'#f3f4f6,#6b7280'}; return <span style={{padding:'1px 8px',fontSize:11,fontWeight:600,borderRadius:9999,background:c[variant].split(',')[0],color:c[variant].split(',')[1]}}>{children}</span>; }

function Dashboard() {
  const [appts, setAppts] = useState<any[]>([]);
  const [search, setSearch] = useState('');
  const [searchResults, setSearchResults] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetch(`${AI}/api/v1/schedule/today`).then(r=>r.json()).then(d=>{ setAppts(d.appointments||[]); setLoading(false); }).catch(()=>setLoading(false));
  }, []);

  const handleSearch = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!search) return;
    try {
      // Redirect to Oscar's patient search
      window.location.href = `/oscar/demographic/demographiccontrol.jsp?displaymode=search&search_mode=search_name&search_name=${encodeURIComponent(search)}&dboperation=search_name`;
    } catch {}
  };

  const now = new Date();
  const dateStr = now.toLocaleDateString('en-CA', {weekday:'long',year:'numeric',month:'long',day:'numeric'});

  return (
    <div style={{minHeight:'100vh',fontFamily:'-apple-system,BlinkMacSystemFont,sans-serif',background:'#f3f4f6'}}>
      {/* HEADER */}
      <div style={{background:'linear-gradient(135deg,#1e3a8a,#2563eb)',color:'#fff',padding:'10px 24px',display:'flex',alignItems:'center',justifyContent:'space-between',boxShadow:'0 2px 12px rgba(0,0,0,0.15)'}}>
        <div style={{display:'flex',alignItems:'center',gap:24}}>
          <h1 style={{fontSize:18,fontWeight:700,margin:0}}>OSCAR McMaster</h1>
          <nav style={{display:'flex',gap:4}}>
            {[{l:'Schedule',h:'/oscar/ai/dashboard.jsp'},{l:'Patients',h:'/oscar/demographic/demographiccontrol.jsp?displaymode=search&search_mode=search_name&dboperation=search_all'},{l:'AI Encounter',h:'/oscar/ai/encounter.jsp'},{l:'Smart Intake',h:'/oscar/ai/intake.jsp'},{l:'Billing',h:'/oscar/ai/billing.jsp'},{l:'Scribe',h:'/oscar/ai/scribe.jsp'}].map(m=><a key={m.l} href={m.h} style={{color:'rgba(255,255,255,0.9)',textDecoration:'none',padding:'4px 10px',borderRadius:4,fontSize:13,transition:'background .15s'}} onMouseOver={e=>e.currentTarget.style.background='rgba(255,255,255,0.15)'} onMouseOut={e=>e.currentTarget.style.background='transparent'}>{m.l}</a>)}
          </nav>
        </div>
        <div style={{display:'flex',alignItems:'center',gap:16}}>
          <form onSubmit={handleSearch} style={{display:'flex',gap:4}}>
            <input value={search} onChange={e=>setSearch(e.target.value)} placeholder="Search patients..." style={{padding:'6px 12px',border:'none',borderRadius:6,fontSize:13,width:200,outline:'none'}} />
          </form>
          <a href="/oscar/logout.jsp" style={{color:'rgba(255,255,255,0.7)',fontSize:12,textDecoration:'none'}}>Logout</a>
        </div>
      </div>

      {/* MAIN CONTENT */}
      <div style={{maxWidth:1100,margin:'0 auto',padding:'20px 24px'}}>
        {/* STATS */}
        <div style={{display:'grid',gridTemplateColumns:'repeat(auto-fit,minmax(180px,1fr))',gap:12,marginBottom:20}}>
          {[
            {label:'Today',value:dateStr.split(',')[0]||'Today',icon:'📅'},
            {label:'Patients',value:appts.length+' scheduled',icon:'👥'},
            {label:'Quick Links',value:'Modules',icon:'⚡'},
          ].map((s,i)=><div key={i} style={{background:'#fff',padding:16,borderRadius:10,border:'1px solid #e5e7eb',boxShadow:'0 1px 3px rgba(0,0,0,0.06)'}}><div style={{fontSize:24,marginBottom:4}}>{s.icon}</div><div style={{fontSize:12,color:'#6b7280',marginBottom:2}}>{s.label}</div><div style={{fontSize:18,fontWeight:700,color:'#1f2937'}}>{s.value}</div></div>)}
        </div>

        {/* SCHEDULE */}
        <div style={{display:'grid',gridTemplateColumns:'2fr 1fr',gap:16}}>
          <div style={{background:'#fff',border:'1px solid #e5e7eb',borderRadius:10,boxShadow:'0 1px 3px rgba(0,0,0,0.06)',overflow:'hidden'}}>
            <div style={{padding:'14px 18px',borderBottom:'1px solid #f3f4f6',display:'flex',justifyContent:'space-between',alignItems:'center'}}>
              <h2 style={{fontSize:16,fontWeight:600,margin:0,color:'#1f2937'}}>Today's Schedule</h2>
              <span style={{fontSize:13,color:'#6b7280'}}>{dateStr}</span>
            </div>
            {loading?<div style={{padding:40,textAlign:'center',color:'#9ca3af'}}>Loading...</div>:
            appts.length===0?<div style={{padding:40,textAlign:'center',color:'#9ca3af'}}>No appointments today</div>:
            <table style={{width:'100%',borderCollapse:'collapse'}}>
              <thead><tr style={{background:'#f9fafb'}}>{['Time','Patient','Provider','Notes'].map(h=><th key={h} style={{padding:'8px 14px',fontSize:11,textTransform:'uppercase',color:'#6b7280',fontWeight:600,textAlign:'left',borderBottom:'2px solid #e5e7eb'}}>{h}</th>)}</tr></thead>
              <tbody>{appts.map((a:any,i:number)=><tr key={i} style={{borderBottom:'1px solid #f3f4f6',cursor:'pointer'}} onClick={()=>a.demographic_no&&(window.location.href=`/oscar/ai/encounter.jsp?demographicNo=${a.demographic_no}`)} onMouseOver={e=>e.currentTarget.style.background='#f0f4ff'} onMouseOut={e=>e.currentTarget.style.background='transparent'}>
                <td style={{padding:'8px 14px',fontSize:13,fontWeight:500}}>{a.start?.substring(0,5)} - {a.end?.substring(0,5)}</td>
                <td style={{padding:'8px 14px',fontSize:13}}>{a.patient}</td>
                <td style={{padding:'8px 14px',fontSize:13,color:'#6b7280'}}>{a.provider_name}</td>
                <td style={{padding:'8px 14px',fontSize:12,color:'#9ca3af'}}>{a.notes?.substring(0,30)}</td>
              </tr>)}</tbody>
            </table>}
          </div>

          {/* QUICK ACTIONS */}
          <div style={{display:'flex',flexDirection:'column',gap:10}}>
            {[
              {t:'New Encounter',d:'Start AI scribe for a patient',h:'/oscar/ai/encounter.jsp',c:'#2563eb'},
              {t:'Smart Intake',d:'Register a new patient with AI',h:'/oscar/ai/intake.jsp',c:'#059669'},
              {t:'Billing',d:'AI billing code suggestions',h:'/oscar/ai/billing.jsp',c:'#7c3aed'},
              {t:'Patient Search',d:'Find and manage patients',h:'/oscar/demographic/demographiccontrol.jsp?displaymode=search',c:'#d97706'},
              {t:'Referrals',d:'Generate and track referrals',h:'/oscar/ai/referral.jsp',c:'#dc2626'},
              {t:'Prescriptions',d:'Manage medications',h:'/oscar/oscarRx/choosePatient.do',c:'#0891b2'},
            ].map((a,i)=><a key={i} href={a.h} style={{display:'block',padding:'14px',background:'#fff',border:'1px solid #e5e7eb',borderRadius:8,borderLeft:`4px solid ${a.c}`,textDecoration:'none',transition:'box-shadow .15s',boxShadow:'0 1px 2px rgba(0,0,0,0.04)'}} onMouseOver={e=>e.currentTarget.style.boxShadow='0 4px 12px rgba(0,0,0,0.1)'} onMouseOut={e=>e.currentTarget.style.boxShadow='0 1px 2px rgba(0,0,0,0.04)'}>
              <div style={{fontSize:14,fontWeight:600,color:'#1f2937'}}>{a.t}</div>
              <div style={{fontSize:12,color:'#6b7280',marginTop:2}}>{a.d}</div>
            </a>)}
          </div>
        </div>
      </div>
    </div>
  );
}

const el = document.getElementById('dashboard-root');
if (el) createRoot(el).render(<Dashboard />);
